import{_ as r,o as t,c as s,a2 as e}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"VuGrid 그리드 통합","description":"","frontmatter":{"title":"VuGrid 그리드 통합","feature_id":"003","status":"done","created":"2026-05-30 13:44 (KST)","tags":["vugrid","grid","frontend","vendoring","agent-ui"]},"headers":[],"relativePath":"specs/003-vugrid-grid-integration/spec.md","filePath":"specs/003-vugrid-grid-integration/spec.md","lastUpdated":null}'),i={name:"specs/003-vugrid-grid-integration/spec.md"};function n(l,o,g,d,a,c){return t(),s("div",null,[...o[0]||(o[0]=[e('<h1 id="spec-vugrid-그리드-통합-vugrid-grid-integration" tabindex="-1">Spec: VuGrid 그리드 통합 (VuGrid Grid Integration) <a class="header-anchor" href="#spec-vugrid-그리드-통합-vugrid-grid-integration" aria-label="Permalink to &quot;Spec: VuGrid 그리드 통합 (VuGrid Grid Integration)&quot;">​</a></h1><blockquote><p>별도 저장소 <code>d:\\ax\\vugrid</code> 에서 <strong>빌드된 산출물</strong>(<code>dist/</code> + 스타일/폰트/이미지 자산)을 이 저장소로 들여와, <strong>에이전트 프로젝트</strong>와 <strong>설계 저널(블로그)</strong> 양쪽에서 데이터 그리드를 사용할 수 있게 한다.</p></blockquote><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>에이전트를 만들 때 <strong>표 형태의 데이터를 보여주고 편집하는 그리드 UI</strong> 가 필요하다. 이미 사내에서 만든 그리드 라이브러리 <strong>VuGrid</strong> 가 있으므로, 새로 만들지 않고 이것을 재사용한다.</p><p>VuGrid 원본 저장소는 이 프로젝트와 분리되어 있고, 소비하는 쪽에서는 <strong>소스를 다시 빌드하고 싶지 않다.</strong> 따라서 VuGrid 가 이미 빌드해 둔 배포 산출물을 이 저장소에 <strong>반입(vendoring)</strong> 해, 빌드 도구·소스 의존 없이 바로 불러 쓸 수 있게 한다.</p><p>소비 주체는 둘이며 <strong>둘 다 필요</strong>하다:</p><ol><li><strong>에이전트 프로젝트</strong> — 에이전트가 데이터를 그리드로 렌더링·편집한다.</li><li><strong>설계 저널(블로그)</strong> — 문서/저널 안에서 그리드를 데모하고 사용한다.</li></ol><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-05-30" tabindex="-1">Session 2026-05-30 <a class="header-anchor" href="#session-2026-05-30" aria-label="Permalink to &quot;Session 2026-05-30&quot;">​</a></h3><ul><li>Q: 블로그(React/Docusaurus)에서 그리드를 마운트하는 방식? → A: VuGrid의 <strong>프레임워크 비의존 코어</strong>를 React <code>ref</code>/<code>useEffect</code> 로 임퍼러티브 마운트한다 (Vue 런타임을 블로그 번들에 동봉하지 않음).</li><li>Q: 빌드 산출물을 레포 어디에 두고 두 표면이 불러올지? → A: 레포 공용 <strong><code>vendor/vugrid/</code></strong> 한 곳을 <strong>단일 출처</strong>로 두고, 블로그·에이전트가 모두 거기서 import 한다(사본 중복 없음).</li><li>Q: 블로그 콘텐츠에서 그리드를 부르는 형태? → A: 재사용 가능한 <strong>MDX/React 컴포넌트 <code>&lt;VuGrid/&gt;</code></strong> 로 만들어 어느 문서·저널에서나 삽입한다.</li><li>Q: Docusaurus SSR/빌드 안전성 처리? → A: 그리드 컴포넌트를 <strong><code>&lt;BrowserOnly&gt;</code></strong> 로 감싸 클라이언트에서만 렌더해 SSR 빌드 실패를 막는다.</li><li>Q: 테마 CSS·폰트·아이콘 로딩 방식? → A: 그리드 컴포넌트에서 테마 CSS를 <strong>직접 import</strong> 한다(스코프 한정·자기완결적).</li></ul><h3 id="session-2026-05-30-구현-중-개정" tabindex="-1">Session 2026-05-30 (구현 중 개정) <a class="header-anchor" href="#session-2026-05-30-구현-중-개정" aria-label="Permalink to &quot;Session 2026-05-30 (구현 중 개정)&quot;">​</a></h3><ul><li><strong>개정</strong>: 블로그 마운트 방식을 &quot;React 코어 직접 마운트&quot;에서 <strong><code>&lt;iframe&gt;</code> 격리</strong>로 변경. 이유: VuGrid 본문 행(<code>.vugrid-row</code>)은 인라인 <code>display:flex</code> 로 셀을 가로 배치하는데, Docusaurus(Infima) 전역 CSS 가 이 div 에 새어 들어와 본문 셀이 세로로 쌓이는 문제 발생. <strong>&quot;vugrid 엔 vugrid 스타일시트만 적용&quot;</strong> 요구를 충족하려면 격리가 필요. 그리드 코어가 <code>document.querySelector</code> 를 쓰므로 Shadow DOM 불가 → iframe 채택.</li><li><strong>연쇄 변경</strong>: 블로그도 에이전트처럼 <strong>정적 서빙 + import map</strong> 으로 통일. 단일 출처 <code>vendor/vugrid/</code> 를 Docusaurus <code>staticDirectories</code> 로 <code>/vugrid/**</code> 서빙(리포 사본 없음, FR-11 유지). 블로그의 <code>file:</code> npm 의존·코어 webpack 번들은 제거.</li></ul><h3 id="session-2026-05-30-구현-마무리" tabindex="-1">Session 2026-05-30 (구현 마무리) <a class="header-anchor" href="#session-2026-05-30-구현-마무리" aria-label="Permalink to &quot;Session 2026-05-30 (구현 마무리)&quot;">​</a></h3><ul><li><strong>반입본 재빌드</strong>: 최초 반입한 <code>dist</code> 가 stale 빌드라 (1) 인라인 필터 입력 값이 유지되지 않고 (2) 본문 행 레이아웃이 빠져 있었다. vugrid 를 현재 소스로 <strong>재빌드(<code>vite build</code>)</strong> 후 재반입하니 본문이 <code>&lt;table&gt;</code>+<code>&lt;colgroup&gt;</code> 구조로 바뀌며 정상 정렬·필터 유지됨. → 반입본의 <strong>버전/렌더링 구조가 곧 계약</strong>.</li><li><strong>그리드 옵션</strong>: <code>&lt;VuGrid/&gt;</code> 에 <code>gridProps</code> prop 추가 → <code>VuGrid.create</code> 3번째 인자로 전달. 인라인 필터는 <code>{showInlineFilter, enableFilter, inlineFilterDelay}</code>.</li></ul><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><p><strong>포함:</strong></p><ul><li>VuGrid의 <strong>빌드 산출물</strong>을 이 저장소의 공용 <strong><code>vendor/vugrid/</code></strong> 한 곳에 반입한다(단일 출처). <ul><li>코어 그리드(프레임워크 비의존), Vue 래퍼, export(PDF/XLSX) 번들</li><li>타입 정의(<code>.d.ts</code>), 스타일 테마(CSS), 폰트, 이미지 자산</li></ul></li><li>반입된 산출물을 <strong>두 소비 표면 모두</strong>에서 <code>vendor/vugrid/</code> 로부터 불러 쓴다. <ul><li><strong>블로그(Docusaurus, React)</strong>: 프레임워크 비의존 <strong>코어</strong>를 React <code>ref</code>/<code>useEffect</code> 로 마운트하는 재사용 컴포넌트 <strong><code>&lt;VuGrid/&gt;</code></strong> 를 만들고, <strong><code>&lt;BrowserOnly&gt;</code></strong> 로 감싸 클라이언트에서만 렌더한다. 테마 CSS는 컴포넌트가 직접 import 한다.</li><li><strong>에이전트 프로젝트</strong>: 그리드를 띄운다.</li></ul></li><li>그리드가 <strong>실제로 렌더링되어 동작</strong>함을 보이는 최소 예시(데모) 1개 이상.</li><li>반입 산출물의 <strong>출처·버전</strong>을 기록(어느 VuGrid 버전에서 왔는지 추적 가능).</li></ul><p><strong>제외(Non-goals):</strong></p><ul><li>VuGrid 자체의 기능 추가·수정·버그픽스. (원본 저장소의 몫)</li><li>VuGrid 소스를 이 저장소에서 다시 <strong>빌드</strong>하는 일.</li><li>에이전트의 실제 화면(데이터 바인딩·도메인 UI) 완성 — 본 기능은 그리드를 <strong>사용 가능하게 만드는 것</strong>까지이며, 구체 화면은 후속 기능.</li><li>그리드를 통해 보여줄 백엔드 데이터 API 설계.</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>As a</strong> 에이전트 개발자, <strong>I want</strong> 반입된 VuGrid를 import 해서 데이터 배열을 넘기면 그리드가 그려지길, <strong>so that</strong> 그리드를 직접 만들지 않고 에이전트 화면에 표를 붙일 수 있다.</li><li><strong>As a</strong> 저널 작성자, <strong>I want</strong> 블로그 문서 안에서 <code>&lt;VuGrid/&gt;</code> 컴포넌트를 삽입해 그리드를 띄울 수 있길, <strong>so that</strong> 그리드 사용 예시를 문서로 보여줄 수 있다.</li><li><strong>As a</strong> 유지보수자, <strong>I want</strong> 반입된 그리드 파일이 어느 VuGrid 버전에서 왔는지 알 수 있길, <strong>so that</strong> 원본이 갱신됐을 때 다시 반입할 수 있다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>FR-1</strong>: VuGrid의 빌드 산출물(코어·Vue 래퍼·export·타입·스타일·폰트·이미지)을 이 저장소의 공용 <strong><code>vendor/vugrid/</code></strong> 한 곳에 반입한다.</li><li><strong>FR-2</strong>: 반입된 산출물은 <strong>원본을 다시 빌드하지 않고</strong> 그대로 사용 가능해야 한다(자기완결적).</li><li><strong>FR-3</strong>: <strong>블로그(React/Docusaurus)</strong> 에서 반입된 그리드를 재사용 컴포넌트 <strong><code>&lt;VuGrid/&gt;</code></strong> 로 불러 <strong>하나 이상의 페이지/문서에서 렌더링</strong>할 수 있어야 한다. 이 컴포넌트는 VuGrid <strong>코어</strong>를 React <code>ref</code>/<code>useEffect</code> 로 마운트한다.</li><li><strong>FR-4</strong>: <strong>에이전트 프로젝트</strong> 에서 반입된 그리드를 불러 <strong>렌더링</strong>할 수 있어야 한다.</li><li><strong>FR-5</strong>: 그리드는 행 데이터 + 컬럼 정의를 입력받아 표로 표시한다(최소 표시 기능 동작 확인).</li><li><strong>FR-6</strong>: 그리드의 <strong>스타일(테마 CSS·폰트·아이콘)</strong> 이 함께 반입되어야 하며, 블로그 컴포넌트는 테마 CSS를 <strong>직접 import</strong> 해 외형이 정상 적용되어야 한다 (스타일 깨짐 없음).</li><li><strong>FR-7</strong>: 반입된 산출물의 <strong>출처와 버전</strong>(VuGrid 버전·반입 일자)을 기록한다.</li><li><strong>FR-8</strong>: 원본 VuGrid 가 갱신되면 <strong>반복 가능한 절차</strong>로 다시 반입할 수 있어야 한다(수동이라도 문서화된 단계).</li><li><strong>FR-9</strong>: 반입으로 인해 기존 블로그 빌드/에이전트 빌드가 <strong>깨지지 않아야</strong> 한다.</li><li><strong>FR-10</strong>: 블로그 그리드 컴포넌트는 <strong><code>&lt;BrowserOnly&gt;</code></strong> 로 감싸 SSR(빌드 시 서버 렌더) 단계에서 평가되지 않고 <strong>클라이언트에서만 렌더</strong>되어야 한다.</li><li><strong>FR-11</strong>: 블로그와 에이전트는 동일한 <strong><code>vendor/vugrid/</code></strong> 단일 출처를 참조한다. 같은 산출물을 표면별로 <strong>중복 사본</strong>으로 두지 않는다.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 개발자가 그리드를 화면에 붙이는 데 <strong>원본 VuGrid 저장소 없이</strong>, 이 저장소만으로 가능하다.</li><li><strong>SC-2</strong>: 블로그에서 <code>&lt;VuGrid/&gt;</code> 를 삽입한 예시 페이지가 <strong>빌드 성공</strong>(SSR 포함) 후 그리드가 <strong>눈에 보이게</strong> 렌더링된다(빈 화면·콘솔 에러 없음).</li><li><strong>SC-3</strong>: 에이전트 프로젝트에서 그리드 예시가 <strong>실행되어 표가 표시</strong>된다.</li><li><strong>SC-4</strong>: 그리드에 <strong>N행 × M열</strong>(예: 10행 5열) 데이터를 넣으면 모든 셀이 정확히 표시된다.</li><li><strong>SC-5</strong>: 어떤 VuGrid 버전이 반입됐는지 저장소만 보고 <strong>1분 내 확인</strong> 가능하다.</li><li><strong>SC-6</strong>: 그리드 외형(테두리·헤더·폰트)이 적용되어 <strong>스타일 미적용 상태로 보이지 않는다.</strong></li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><ul><li><strong>VuGrid 배포 번들</strong>: 반입 대상. ESM/CJS 모듈, 타입 정의, 테마 CSS, 폰트, 이미지로 구성. 진입점은 코어 / Vue / export(pdf·xlsx)로 나뉜다. 저장 위치는 공용 <code>vendor/vugrid/</code>.</li><li><strong><code>&lt;VuGrid/&gt;</code> 블로그 컴포넌트</strong>: VuGrid 코어를 감싼 React/MDX 컴포넌트. <code>&lt;BrowserOnly&gt;</code> 로 클라이언트 전용 렌더, 테마 CSS 직접 import.</li><li><strong>소비 표면(2종)</strong>: ① 블로그(React/Docusaurus), ② 에이전트 프로젝트.</li><li><strong>반입 출처 기록</strong>: VuGrid 버전·반입 일자·원본 경로 등 추적 메타데이터.</li></ul><h2 id="assumptions" tabindex="-1">Assumptions <a class="header-anchor" href="#assumptions" aria-label="Permalink to &quot;Assumptions&quot;">​</a></h2><ul><li>&quot;build된 파일&quot;은 VuGrid 저장소의 <code>dist/</code> 모듈 산출물과 <code>style/</code>(테마·폰트· 이미지) 자산 전체를 가리킨다. (export용 PDF/XLSX 진입점 포함)</li><li>블로그는 <strong>React 기반 Docusaurus</strong> 이므로, Vue 래퍼가 아닌 VuGrid 의 <strong>프레임워크 비의존 코어</strong>로 그리드를 마운트한다. (Clarifications 확정)</li><li>반입 위치는 레포 공용 <strong><code>vendor/vugrid/</code></strong> 단일 출처다. (Clarifications 확정)</li><li>에이전트 프로젝트의 그리드 호스트(웹 화면)는 본 기능에서 <strong>최소 데모 수준</strong>으로만 만들고, 완전한 에이전트 UI는 후속 기능으로 분리한다.</li><li>반입은 <strong>빌드 산출물 복사(스냅샷)</strong> 방식이며, 원본을 npm 레지스트리로 게시하는 것은 가정하지 않는다.</li><li>양쪽 표면 모두 그리드는 <strong>브라우저(클라이언트)</strong> 에서 렌더링된다.</li><li>블로그 <code>&lt;VuGrid/&gt;</code> 의 <code>theme</code> 은 현 단계 <strong><code>default</code> 만 지원</strong>(M1). 다중 테마는 후속 작업으로 분리.</li><li>에이전트 정적 서빙 위치는 설정값 <strong><code>vugrid.vendor-location</code></strong> 으로 외부화(M2).</li></ul><h2 id="edge-cases" tabindex="-1">Edge Cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge Cases&quot;">​</a></h2><ul><li>VuGrid 가 요구하는 런타임 의존(예: 이벤트 버스 <code>mitt</code>, export 시 exceljs/ pdfkit/jszip 같은 선택 의존)이 반입 번들에 빠지면 로드 실패 → 필요한 런타임 의존의 동봉/설치 방침이 정해져 있어야 한다.</li><li>블로그(React)에서 실수로 Vue 전용 진입점을 부르면 마운트 실패 → 블로그는 <strong>코어 진입점만</strong> 사용하도록 <code>&lt;VuGrid/&gt;</code> 컴포넌트로 강제한다. (Clarifications 로 해소)</li><li>Docusaurus SSR 단계에서 브라우저 전용 코드가 평가되면 빌드 실패 → <code>&lt;BrowserOnly&gt;</code> 로 차단한다. (Clarifications 로 해소)</li><li>테마 CSS/폰트 경로가 어긋나면 그리드는 뜨지만 <strong>스타일이 깨진다.</strong></li><li>반입 산출물 용량(약 2.3MB+)이 저장소·번들 크기에 주는 영향.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>[ ] <strong>에이전트 프론트엔드 형태</strong>: 별도 프론트엔드 앱 신설 vs. Spring Boot 정적 리소스 서빙 vs. 기존 수단 활용 — 어느 쪽인가. (에이전트 측 한정; 블로그 방법은 Clarifications 에서 확정됨)</li><li>[ ] <strong>번들 범위 확정</strong>: export(PDF/XLSX) 진입점과 모든 테마를 전부 반입할지, 코어+기본 테마만 반입할지.</li><li>[ ] <strong>런타임 의존 처리</strong>: <code>mitt</code> 및 export용 선택 의존을 동봉할지, 소비 측에서 설치할지.</li><li>[ ] <strong>재반입(동기화) 자동화</strong>: 기존 <code>scripts/sync-*</code> 스타일의 복사 스크립트로 자동화할지, 수동 절차 문서화로 충분한지.</li></ul>',33)])])}const p=r(i,[["render",n]]);export{h as __pageData,p as default};
